const { Manifold, CrossSection, setCircularSegments } = api;
setCircularSegments(64);

const bodyH = 30;
const bodyR = 6;
const body = Manifold.cylinder(bodyH, bodyR, bodyR * 0.95, 64);

// Nose ogive
const noseH = 14;
const noseProfile = [[0, 0]];
const samples = 24;
for (let i = 0; i <= samples; i++) {
  const t = i / samples;
  const r = bodyR * 0.95 * Math.cos(t * Math.PI / 2);
  const y = noseH * t;
  if (i === 0) noseProfile.push([bodyR * 0.95, 0]);
  else noseProfile.push([Math.max(r, 0.01), y]);
}
noseProfile.push([0, noseH]);
const noseCS = CrossSection.ofPolygons([noseProfile]);
const nose = Manifold.revolve(noseCS, 64).translate([0, 0, bodyH - 0.5]);

const collar = Manifold.cylinder(1.2, bodyR + 0.6, bodyR + 0.6, 64).translate([0, 0, bodyH - 0.6]);
const baseRing = Manifold.cylinder(1.5, bodyR + 0.4, bodyR + 0.4, 64);

// Fins
const finProfile = [[0, 0], [bodyR + 5, 0], [0, 12]];
const finCS = CrossSection.ofPolygons([finProfile]);
let fin = finCS.extrude(0.8, 0, 0, 1, true);
fin = fin.rotate([90, 0, 0]);
fin = fin.translate([bodyR - 0.5, 0, 0]);
const finsList = [];
for (let i = 0; i < 3; i++) {
  finsList.push(fin.rotate([0, 0, (360 / 3) * i]));
}
const fins = Manifold.union(finsList);

// Window
const windowR = 1.8;
const windowZ = bodyH * 0.65;
const windowCutter = Manifold.cylinder(3, windowR, windowR, 32).rotate([90, 0, 0]).translate([0, -bodyR - 0.5, windowZ]);

const frameOuter = Manifold.cylinder(1.0, windowR + 0.6, windowR + 0.6, 32).rotate([90, 0, 0]).translate([0, -bodyR + 0.2, windowZ]);
const frameInner = Manifold.cylinder(1.5, windowR + 0.1, windowR + 0.1, 32).rotate([90, 0, 0]).translate([0, -bodyR + 0.1, windowZ]);
const frame = frameOuter.subtract(frameInner);

// Nozzle: bottom at z=-4, top at z=1 (overlaps base ring). 
// Hole goes ALL the way through (from below the nozzle bottom up into body interior cavity).
// To avoid sealing the cavity, we'll punch the hole upward through the body floor.
const nozzleH = 4;
const nozzle = Manifold.cylinder(nozzleH, 3.5, 5, 64).translate([0, 0, -nozzleH + 1]);
// Hole spans from z=-5 (below) up to z=2 (into body). This carves a tunnel from
// outside-below into body interior, but since body is solid the tunnel ends at
// ... actually we want to NOT seal the cavity. Make hole break through bottom only.
const nozzleHole = Manifold.cylinder(nozzleH + 1, 2.9, 4.4, 64).translate([0, 0, -nozzleH + 0.5]);
// Now hole spans z = -3.5 to 1.5, which goes ABOVE z=0 into the body. Subtracting from
// (body+nozzle) creates a tunnel from outside-bottom into body interior. Body interior
// is solid so the tunnel just dead-ends — same problem.
// SOLUTION: also subtract a smaller cylinder from the body interior to make a thrust chamber
// that connects out through the nozzle. This forms one connected open cavity.
const thrustChamber = Manifold.cylinder(6, 2.9, 2.9, 64).translate([0, 0, 1]);

let rocket = body;
rocket = rocket.add(nose);
rocket = rocket.add(collar);
rocket = rocket.add(baseRing);
rocket = rocket.add(fins);
rocket = rocket.subtract(windowCutter);
rocket = rocket.add(frame);
rocket = rocket.add(nozzle);
rocket = rocket.subtract(nozzleHole);
rocket = rocket.subtract(thrustChamber);

return rocket;
